<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header theme-primary">
                    <h4 class="modal-title">{{ $t('Replies') }}</h4>
                    <button class="close" @click="Close">
                        <em class="fa fa-times"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <div class="heading-border">
                        <h5 class="h5"><span>Ticket History</span></h5>
                    </div>
                    <div v-if="replies && replies.length">
                        <div v-for="(reply, index) in replies" :key="index" class="conversation-box mb-3">
                            <div class="name-circle light-grey">
                                <em class="fa fa-user"></em>
                            </div>
                            <div class="conversation-content">
                                <div v-html="reply.COMMENT"></div>
                                <span class="blue-time"> {{ reply.CREATED_BY }} </span> | {{ formatDateTime(reply.CREATED_AT) }}
                            </div>
                        </div>
                    </div>
                    <div v-else class="text-center text-danger">
                        {{ $t('NorecordfoundText') }}
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-danger" @click="Close">
                        {{ $t('Close') }}
                    </button>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataServices from "../../services/DataService";

export default {
    props: {
        ticketId: [String, Number]
    },
    data() {
        return {
            isLoading: false,
            replies: []
        };
    },
    created: async function () {
        var vm = this;
        await vm.GetCommentsByTicketId();
    },
    methods: {
        GetCommentsByTicketId: async function () {
            var vm = this;
            vm.isLoading = true;
            var params = `TicketId=${vm.ticketId} `;
            await DataServices.GetCommentsByTicketId(params).then((response) => {
                vm.isLoading = false;
                vm.replies = [];
                vm.replies = response.data;
            });
        },
        formatDateTime(datetime) {
            if (!datetime) return '';

            const date = new Date(datetime);

            const month = date.getMonth() + 1;
            const day = date.getDate();
            const year = date.getFullYear();

            let hours = date.getHours();
            const minutes = String(date.getMinutes()).padStart(2, '0');
            const seconds = String(date.getSeconds()).padStart(2, '0');

            const ampm = hours >= 12 ? 'PM' : 'AM';
            hours = hours % 12 || 12;

            return `${month}/${day}/${year} ${hours}:${minutes}:${seconds} ${ampm}`;
        },
        Close() {
            this.$parent.isShowViewReply = false;
        }
    }
};
</script>