<template>
  <div>

    <!-- Wait until privilege check finishes -->
    <div v-if="isChecking"></div>

    <!-- Show Report Content -->
    <slot v-else-if="hasPrivilege"></slot>

    <!-- Unauthorized Message -->
    <div v-else class="text-center mt-5">
      <i class="fa fa-lock fa-4x text-danger mb-3"></i>
      <!-- <h3>Unauthorized Access</h3>
      <p>You don't have permission to access this report.</p> -->
       <h3>{{ $t('UnAuthorizedAccess') }}</h3>
      <p>{{ $t('NoPermissionToAccessReport') }}</p>
    </div>

  </div>
</template>

<script>
import DataServices from "@/services/DataService";

export default {
  name: "Unauthorized",
  props: {
    controller: String,
    action: String
  },
  data() {
    return {
      hasPrivilege: false,
      isChecking: true
    };
  },
  async created() {
    try {
      const params = `controller=${this.controller}&action=${this.action}`;
      const response = await DataServices.CheckPrivilege(params);
      this.hasPrivilege = response.data;
    } catch (err) {
      console.error("Privilege check error:", err);
      this.hasPrivilege = false;
    } finally {
      this.isChecking = false;
    }
  }
};
</script>