    <ViewTicketReplies v-if="isShowViewReply" :ticketId="ticketId" @close="isShowViewReply = false" />
    <ViewTicketAttachments v-if="isShowViewAttachment" :ticketId="ticketId" @close="isShowViewAttachment = false" />
    <ViewTicketNotes v-if="isShowViewNote" :ticketId="ticketId" @close="isShowViewNote = false" />
    </section>
</template>

