                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('CONTRACTNAME'), name: "ContractName", value: "", placeholder: this.$t('SelectClient'),
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, active: true, inactive: true, clear: true }, itemFields: ['text', 'status'], isMultiple: true, groupFields: ['groupText'], minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' }, onChange: this.onSelectionChange },
                        validationRules: { "required": false }
