                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Status'), name: "Status", value: "", placeholder: "Select Status",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
