                            format: "MM/DD/YYYY", maxDate: false, onChange: this.setTimerDate,
                            datePickerConfig: { useCurrent: true, showClear: true, showClose: true, allowInputToggle: false, minDate: true, maxDate: true, widgetPositioning: { horizontal: 'right', vertical: 'bottom' } },
                            secondDatePickerConfig: { useCurrent: false, showClear: true, showClose: true, allowInputToggle: false, minDate: true, maxDate: false, widgetPositioning: { horizontal: 'right', vertical: 'bottom' } }
                        },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Product'), name: "Product", value: "", placeholder: "Select Product",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Channel'), name: "Channel", value: "", placeholder: "Select Channel",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    }
                ]
            }],
            FormSchema1: [{
                layoutType: "triple",
                Data: [
                    {
                        astype: "SearchableSelectField", label: this.$t('Assign Department'), name: "AssignDepartment1", value: "", placeholder: "Select Assign Department",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    }
                ]
            }],
            FormSchema2: [{
                layoutType: "triple",
                Data: [
                    { astype: "TextField", label: "Ticket Number", name: "TicketNumber2", value: "", placeholder: "Enter Ticket Number", validationRules: { "required": false } },
                    { astype: "TextField", label: "Subject", name: "Subject2", value: "", placeholder: "Enter Subject", validationRules: { "required": false } },
                    {
                        astype: "SearchableSelectField", label: this.$t('Submitted By'), name: "SubmittedBy2", value: "", placeholder: "Select Submitted By",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Assigned To'), name: "AssignedTo2", value: "", placeholder: "Select Assigned To",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('CONTRACTNAME'), name: "ContractName2", value: "", placeholder: this.$t('SelectClient'),
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, active: true, inactive: true, clear: true }, itemFields: ['text', 'status'], isMultiple: true, groupFields: ['groupText'], minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' }, onChange: this.onSelectionChange },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Priority'), name: "Priority2", value: "", placeholder: "Select Priority",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Assign Department'), name: "AssignDepartment2", value: "", placeholder: "Select Assign Department",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Status'), name: "Status2", value: "", placeholder: "Select Status",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "SearchableSelectField", label: this.$t('Category'), name: "Category2", value: "", placeholder: "Select Category",
                        visibility: true, isSearch: true,
                        config: { options: [], actionButtons: { selectAll: true, clear: true }, groupFields: [], isMultiple: true, minSearchLength: 0, statusFieldConfig: { fieldName: 'status', activeValues: ['Active', 'active'], inactiveValues: ['Inactive', 'inactive'], activeColor: '#28a745', inactiveColor: '#dc3545' } },
                        validationRules: { "required": false }
                    },
                    {
                        astype: "DateRangeField", label: this.$t('Opened Date (MM/DD/YYYY)'), name: "TicketDateFrom2", value: "", placeholder: "",
                        config: {
                            format: "MM/DD/YYYY", maxDate: false, onChange: this.setTimerDate,
                            datePickerConfig: { useCurrent: true, showClear: true, showClose: true, allowInputToggle: false, minDate: true, maxDate: true, widgetPositioning: { horizontal: 'right', vertical: 'bottom' } },
                            secondDatePickerConfig: { useCurrent: false, showClear: true, showClose: true, allowInputToggle: false, minDate: true, maxDate: false, widgetPositioning: { horizontal: 'right', vertical: 'bottom' } }
                        },
                        validationRules: { "required": false }
                    }
                ]
            }],
            buttons: [
                { type: "submit", class: "btn btn-success", text: "<i class='fa fa-search pr-2'></i>Search" },
                { type: "button", class: "btn btn-danger", text: "<i class='fa fa-close pr-2'></i>Clear All", onClick: this.onClear }
            ],

            SearchText: '',
            activeKey: 1,
            isLoading: false,
            reportPath: null,
            parameter: [],
            TicketSummarytab: true,
            TicketPrivilegeTab: false,
            TicketDetailsTab: false,
            headerText: 'Ticket Summary Report',
            reportcomponentkey: 0,
            ClientData: '',
            isShowViewDescription: false,
            isShowViewReply: false,
            isShowViewAttachment: false,
            isShowViewNote: false,
            commentId: null,
            ticketId: null
        }
    },
    async created() {
        await this.loadSummaryTabData();
    },
    mounted() {
        this.initializeTabFromRoute();
        window.handleViewDescription = (commentId) => {
            this.openDescriptionPopup(commentId);
        };
        window.handleViewReply = (ticketId) => {
            this.openReplyPopup(ticketId);
        };
        window.handleViewAttachment = (ticketId) => {
            this.openAttachmentPopup(ticketId);
        };
        window.handleViewNote = (ticketId) => {
            this.openNotePopup(ticketId);
        };
    },
    beforeDestroy() {
        delete window.handleViewDescription;
        delete window.handleViewReply;
        delete window.handleViewAttachment;
        delete window.handleViewNote;
    },
    watch: {
        '$route'(to, from) {
            if (to.path === '/TicketReport/Index') {
                this.initializeTabFromRoute();
            }
        }
    },
    methods: {
        formatDate(value) {
            if (!value) return null;
            const m = moment(value);
            return m.isValid() ? m.format('MM-DD-YYYY') : null;
        },
        SearchTab: function () {
            const val = this.SearchText.toLowerCase();
            $("ul#myTab").find("li").each(function () {
                const text = $(this).find("a").text().toLowerCase();
                $(this).toggle(text.includes(val));
            });
        },
        async loadSummaryTabData() {
            if (!this.$refs.TicketSummaryForm) return;

            await Promise.all([
                this.GetUserList(),
                this.fetchclientlist(),
                this.GetPriorityList(),
                this.GetAllDepartmentList(),
                this.GetTicketStatus(),
                this.GetCategory(),
                this.GetProductsList(),
                this.GetChannelList()
            ]);
        },
        async loadPrivilegeTabData() {
            if (!this.$refs.TicketPrivilegeForm) return;
            await this.GetAllDepartmentList();
        },
        async loadDetailsTabData() {
            if (!this.$refs.TicketDetailsForm) return;

            await Promise.all([
                this.GetUserList(),
                this.fetchclientlist(),
                this.GetPriorityList(),
                this.GetAllDepartmentList(),
                this.GetTicketStatus(),
                this.GetCategory()
            ]);
        },
        openDescriptionPopup(commentId) {
            const vm = this;
            vm.commentId = commentId;
            vm.isShowViewDescription = true;
        },
        openReplyPopup(ticketId) {
            const vm = this;
            vm.ticketId = ticketId;
            vm.isShowViewReply = true;
        },
        openAttachmentPopup(ticketId) {
            const vm = this;
            vm.ticketId = ticketId;
            vm.isShowViewAttachment = true;
        },
        openNotePopup(ticketId) {
            const vm = this;
            vm.ticketId = ticketId;
            vm.isShowViewNote = true;
        },
        async loadData(tabName) {
            this.isLoading = true;

            if (tabName === 'TicketSummary') {
                this.activeKey = 1;
                this.TicketSummarytab = true;
                this.TicketPrivilegeTab = false;
                this.TicketDetailsTab = false;
                this.headerText = 'Ticket Summary Report';
                await this.loadSummaryTabData();
            }
            else if (tabName === 'TicketPrivilege') {
                this.activeKey = 2;
                this.TicketSummarytab = false;
                this.TicketPrivilegeTab = true;
                this.TicketDetailsTab = false;
                this.headerText = 'Ticket Privilege Report';
                await this.loadPrivilegeTabData();
            }
            else if (tabName === 'TicketDetails') {
                this.activeKey = 3;
                this.TicketSummarytab = false;
                this.TicketPrivilegeTab = false;
                this.TicketDetailsTab = true;
                this.headerText = 'Ticket Details Report';
                await this.loadDetailsTabData();
            }

            this.parameter = [];
            this.reportcomponentkey += 1;

            const encodedTabName = this.encodeTabName(tabName);
            if (this.$route.query.tab !== encodedTabName) {
                this.$router.push({
                    path: '/TicketReport/Index',
                    query: { tab: encodedTabName }
                }).catch(err => {
                    if (err.name !== 'NavigationDuplicated') console.error(err);
                });
            }

            this.isLoading = false;
        },
        encodeTabName(tabName) {
            return encodeURIComponent(tabName);
        },
        decodeTabName(encodedName) {
            try {
                return decodeURIComponent(encodedName);
            } catch {
                return encodedName;
            }
        },
        initializeTabFromRoute() {
            const tabParam = this.$route.query.tab;
            let tabToLoad = 'TicketSummary';

            if (tabParam) {
                const decoded = this.decodeTabName(tabParam);
                if (['TicketSummary', 'TicketPrivilege', 'TicketDetails'].includes(decoded)) {
                    tabToLoad = decoded;
                }
            }

            this.loadData(tabToLoad);
        },
        onClear: function () {
            const vm = this;
            if (vm.activeKey === 1 && vm.$refs.TicketSummaryForm) {
                const form = vm.$refs.TicketSummaryForm;
                if (form.resetForm) {
                    form.resetForm();
                } else {
                    form.updateProperty("TicketNumber", "value", "");
                    form.updateProperty("Subject", "value", "");
                    form.updateProperty("SubmittedBy", "value", []);
                    form.updateProperty("AssignedTo", "value", []);
                    form.updateProperty("ContractName", "value", []);
                    form.updateProperty("Priority", "value", []);
                    form.updateProperty("AssignDepartment", "value", []);
                    form.updateProperty("Status", "value", []);
                    form.updateProperty("Category", "value", []);
                    form.updateProperty("Product", "value", []);
                    form.updateProperty("Channel", "value", []);
                    form.updateProperty("TicketDateFrom", "value", "");
                    form.updateProperty("TicketDateFrom", "secondValue", "");
                    form.UpdateKeyValue();
                }
            }
            else if (vm.activeKey === 2 && vm.$refs.TicketPrivilegeForm) {
                const form = vm.$refs.TicketPrivilegeForm;
                if (form.resetForm) {
                    form.resetForm();
                } else {
                    form.updateProperty("AssignDepartment1", "value", []);
                    form.UpdateKeyValue();
                }
            }
            else if (vm.activeKey === 3 && vm.$refs.TicketDetailsForm) {
                const form = vm.$refs.TicketDetailsForm;
                if (form.resetForm) {
                    form.resetForm();
                } else {
                    form.updateProperty("TicketNumber2", "value", "");
                    form.updateProperty("Subject2", "value", "");
                    form.updateProperty("SubmittedBy2", "value", []);
                    form.updateProperty("AssignedTo2", "value", []);
                    form.updateProperty("ContractName2", "value", []);
                    form.updateProperty("Priority2", "value", []);
                    form.updateProperty("AssignDepartment2", "value", []);
                    form.updateProperty("Status2", "value", []);
                    form.updateProperty("Category2", "value", []);
                    form.updateProperty("TicketDateFrom2", "value", "");
                    form.updateProperty("TicketDateFrom2", "secondValue", "");
                    form.UpdateKeyValue();
                }
